<pre class="wp-block-code"><code lang="cpp" class="language-cpp">#include&lt;bits/stdc++.h&gt;
using namespace std;

class Solution {
public:
	vector&lt;int&gt; topo(int N, vector&lt;int&gt; adj[]) {
        queue&lt;int&gt; q; 
	    vector&lt;int&gt; indegree(N, 0); 
	    for(int i = 0;i&lt;N;i++) {
	        for(auto it: adj[i]) {
	            indegree[it]++; 
	        }
	    }

	    for(int i = 0;i&lt;N;i++) {
	        if(indegree[i] == 0) {
	            q.push(i); 
	        }
	    }
	    vector&lt;int&gt; topo;
	    while(!q.empty()) {
	        int node = q.front(); 
	        q.pop(); 
	        topo.push_back(node);
	        for(auto it : adj[node]) {
	            indegree[it]--;
	            if(indegree[it] == 0) {
	                q.push(it); 
	            }
	        }
	    }
	    return topo;
	}
};



int main()
{

    	vector&lt;int&gt; adj[6];
    	adj[5].push_back(2);
    	adj[5].push_back(0);
    	adj[4].push_back(0);
    	adj[4].push_back(1);
    	adj[3].push_back(1);
    	adj[2].push_back(3);

    	Solution obj;
    	vector&lt;int&gt; v=obj.topo(6, adj);
    	for(auto it:v)
    	cout&lt;&lt;it&lt;&lt;" ";


    return 0;
}</code></pre>
