<pre class="wp-block-code"><code lang="java" class="language-java">import java.util.*;
import java.io.*;
import java.lang.*;

    class Solution
    {
            public boolean isCyclic(int N, ArrayList&lt;ArrayList&lt;Integer&gt;&gt; adj) {
                int topo[] = new int[N];
                int indegree[] = new int[N];

                //finding indegree
                for(int i = 0;i&lt;N;i++) {
                    for(Integer it: adj.get(i)) {
                        indegree[it]++;
                    }
                }


                Queue&lt;Integer&gt; q = new LinkedList&lt;Integer&gt;();
                for(int i = 0;i&lt;N;i++) {
                    //adding nodes to queue with indegree = 0
                    if(indegree[i] == 0) {
                        q.add(i);
                    }
                }

                int cnt = 0;
                int ind=0;

                while(!q.isEmpty()) {
                    Integer node = q.poll();
                    topo[ind++] = node;
                    cnt++;
                    //getting neighbour nodes of popped node and decreasing  their 
                    indegree by1
                    for(Integer it: adj.get(node)) {
                        indegree[it]--;
                        if(indegree[it] == 0) {
                            q.add(it);
                        }
                    }
                }
                 //printing topological ordering of nodes
                for (int i=0;i&lt; topo.length;i++){
                    System.out.print(topo[i]+" ");
                }
                if(cnt == N) return false;
                return true;
            }
        }
public class TopoLogicalSortBFS {
        public static void main(String args[]) {

            ArrayList &lt; ArrayList &lt; Integer &gt;&gt; adj = new ArrayList &lt; &gt; ();

            // adding new arraylists to 'adj' to add neighbour nodes
            for (int i = 0; i &lt; 6; i++) {
                adj.add(new ArrayList &lt; &gt; ());
            }


            adj.get(5).add(2);
            adj.get(5).add(0);
            adj.get(4).add(0);
            adj.get(4).add(1);
            adj.get(3).add(1);
            adj.get(2).add(3);


           new Solution().isCyclic(6,adj);

        }
    }
